1	import { useState, useRef, useCallback } from "react";
2	import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
3	import { apiRequest } from "@/lib/queryClient";
4	import { Button } from "@/components/ui/button";
5	import { Input } from "@/components/ui/input";
6	import { Textarea } from "@/components/ui/textarea";
7	import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogFooter } from "@/components/ui/dialog";
8	import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
9	import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
10	import { Label } from "@/components/ui/label";
11	import { useToast } from "@/hooks/use-toast";
12	import {
13	  Upload, Video, Link2, Play, Trash2, Eye, Clock, TrendingUp,
14	  Plus, Activity, Target, BarChart3, Code2, Lock, Unlock, Copy,
15	  Check, Film, Zap, Shield, Timer, MousePointer, Hash, ChevronDown,
16	  RefreshCw, Settings2, ExternalLink, AlertCircle, Layers,
17	} from "lucide-react";
18	import { format } from "date-fns";
19	
20	const GOLD = "#d4b461";
21	
22	const PROGRESS_BAR_PRESETS = [
23	  { id: "slow-start", name: "Slow Start", desc: "Starts slow (20%), then speeds up", segments: "0-25%: 40s, 25-50%: 20s, 50-75%: 15s, 75-100%: 10s" },
24	  { id: "steady",     name: "Steady Progress", desc: "Consistent speed throughout", segments: "0-100%: Even pace" },
25	  { id: "fast-start", name: "Fast Start", desc: "Starts fast, then slows down", segments: "0-25%: 10s, 25-50%: 15s, 50-75%: 20s, 75-100%: 30s" },
26	  { id: "custom",     name: "Custom Segments", desc: "Define your own timing", segments: "Custom" },
27	];
28	
29	function EmbedDialog({ video, onClose }: { video: any; onClose: () => void }) {
30	  const [copied, setCopied] = useState(false);
31	  const baseUrl = typeof window !== "undefined" ? window.location.origin : "";
32	  const iframeCode = `<iframe src="${baseUrl}/watch-video/${video.id}" width="100%" height="480" frameborder="0" allowfullscreen style="border-radius:12px;"></iframe>`;
33	  const directUrl = `${baseUrl}/watch-video/${video.id}`;
34	
35	  const copy = (text: string) => {
36	    navigator.clipboard.writeText(text);
37	    setCopied(true);
38	    setTimeout(() => setCopied(false), 2000);
39	  };
40	
41	  return (
42	    <Dialog open onOpenChange={onClose}>
43	      <DialogContent className="bg-zinc-900 border-zinc-700 max-w-lg">
44	        <DialogHeader>
45	          <DialogTitle className="text-white font-bold flex items-center gap-2">
46	            <Code2 className="w-4 h-4" style={{ color: GOLD }} /> Embed: {video.title}
47	          </DialogTitle>
48	        </DialogHeader>
49	        <div className="space-y-4 py-2">
50	          <div>
51	            <Label className="text-xs text-zinc-400 mb-2 block">Embed Code (iframe)</Label>
52	            <div className="relative">
53	              <pre className="text-xs text-zinc-300 bg-zinc-800 rounded-lg p-3 overflow-x-auto whitespace-pre-wrap break-all border border-zinc-700">{iframeCode}</pre>
54	              <button onClick={() => copy(iframeCode)} className="absolute top-2 right-2 p-1.5 rounded-lg hover:bg-zinc-700 transition-colors">
55	                {copied ? <Check className="w-3.5 h-3.5 text-green-400" /> : <Copy className="w-3.5 h-3.5 text-zinc-400" />}
56	              </button>
57	            </div>
58	          </div>
59	          <div>
60	            <Label className="text-xs text-zinc-400 mb-2 block">Direct Player URL</Label>
61	            <div className="flex gap-2">
62	              <Input readOnly value={directUrl} className="bg-zinc-800 border-zinc-700 text-zinc-300 text-xs font-mono" />
63	              <Button variant="outline" size="sm" onClick={() => copy(directUrl)} className="border-zinc-700 text-zinc-300 gap-1">
64	                {copied ? <Check className="w-3 h-3" /> : <Copy className="w-3 h-3" />}
65	              </Button>
66	            </div>
67	          </div>
68	          {video.leadGateEnabled && (
69	            <div className="flex items-center gap-2 px-3 py-2 rounded-lg text-xs font-medium" style={{ background: "#f59e0b18", color: "#f59e0b", border: "1px solid #f59e0b30" }}>
70	              <Lock className="w-3.5 h-3.5" /> Lead gate is active — viewers must register before watching
71	            </div>
72	          )}
73	        </div>
74	        <DialogFooter>
75	          <Button variant="ghost" onClick={onClose} className="text-zinc-400">Close</Button>
76	        </DialogFooter>
77	      </DialogContent>
78	    </Dialog>
79	  );
80	}
81	
82	function VideoTypeBadge({ type }: { type: string }) {
83	  const cfg = type === "vsl"
84	    ? { label: "VSL", bg: "#a78bfa20", color: "#a78bfa", border: "#a78bfa40" }
85	    : type === "webinar"
86	    ? { label: "Webinar", bg: `${GOLD}15`, color: GOLD, border: `${GOLD}35` }
87	    : { label: "Standard", bg: "rgba(255,255,255,0.06)", color: "#a1a1aa", border: "rgba(255,255,255,0.1)" };
88	  return (
89	    <span className="text-[10px] font-black uppercase tracking-wider px-2 py-0.5 rounded-full" style={{ background: cfg.bg, color: cfg.color, border: `1px solid ${cfg.border}` }}>
90	      {cfg.label}
91	    </span>
92	  );
93	}
94	
95	function VideoStatusPills({ video }: { video: any }) {
96	  return (
97	    <div className="flex flex-wrap gap-1">
98	      {video.leadGateEnabled && (
99	        <span className="text-[9px] font-bold px-1.5 py-0.5 rounded-full flex items-center gap-0.5" style={{ background: "#f59e0b18", color: "#f59e0b", border: "1px solid #f59e0b30" }}>
100	          <Lock className="w-2.5 h-2.5" /> GATED
101	        </span>
102	      )}
103	      {video.urgencyText && (
104	        <span className="text-[9px] font-bold px-1.5 py-0.5 rounded-full flex items-center gap-0.5" style={{ background: `${GOLD}12`, color: `${GOLD}99`, border: `1px solid ${GOLD}25` }}>
105	          <Timer className="w-2.5 h-2.5" /> URGENCY
106	        </span>
107	      )}
108	      {video.expiresAt && (
109	        <span className="text-[9px] font-bold px-1.5 py-0.5 rounded-full flex items-center gap-0.5" style={{ background: "#71717a18", color: "#a1a1aa", border: "1px solid #71717a30" }}>
110	          <Clock className="w-2.5 h-2.5" /> EXPIRY
111	        </span>
112	      )}
113	      {video.resumeEnabled && (
114	        <span className="text-[9px] font-bold px-1.5 py-0.5 rounded-full flex items-center gap-0.5" style={{ background: "#22c55e18", color: "#4ade80", border: "1px solid #22c55e30" }}>
115	          <RefreshCw className="w-2.5 h-2.5" /> RESUME
116	        </span>
117	      )}
118	    </div>
119	  );
120	}
121	
122	function VideoRow({
123	  video, onDelete, onToggleLeadGate, onEmbed, onStudio, onAnalytics, seed
124	}: {
125	  video: any;
126	  onDelete: (id: string) => void;
127	  onToggleLeadGate: (id: string, cur: boolean) => void;
128	  onEmbed: (v: any) => void;
129	  onStudio: () => void;
130	  onAnalytics: () => void;
131	  seed: number;
132	}) {
133	  const watchRate = Math.round(40 + seed * 4.5);
134	  const ctaClicks = (video.views || 0) > 0 ? Math.floor((video.views || 0) * (0.05 + seed * 0.008)) : 0;
135	
136	  return (
137	    <div className="group px-5 py-4 flex items-center gap-4 transition-all hover:bg-white/[0.025]" style={{ borderBottom: `1px solid ${GOLD}08` }}>
138	      {/* Thumbnail circle */}
139	      <div className="w-10 h-10 rounded-xl flex items-center justify-center flex-shrink-0 relative" style={{
140	        background: video.videoType === "vsl" ? "#a78bfa20" : `${GOLD}15`,
141	        border: `1px solid ${video.videoType === "vsl" ? "#a78bfa40" : `${GOLD}25`}`,
142	      }}>
143	        {video.thumbnailUrl
144	          ? <img src={video.thumbnailUrl} alt="" className="w-full h-full rounded-xl object-cover" />
145	          : video.videoType === "vsl"
146	          ? <Zap className="w-4 h-4" style={{ color: "#a78bfa" }} />
147	          : <Film className="w-4 h-4" style={{ color: GOLD }} />
148	        }
149	      </div>
150	
151	      {/* Title + meta */}
152	      <div className="flex-1 min-w-0">
153	        <div className="flex items-center gap-2 mb-1 flex-wrap">
154	          <p className="text-sm font-bold text-white truncate max-w-xs">{video.title}</p>
155	          <VideoTypeBadge type={video.videoType || "standard"} />
156	        </div>
157	        <div className="flex items-center gap-3 flex-wrap">
158	          <span className="text-[10px] text-zinc-500 flex items-center gap-1">
159	            <Eye className="w-2.5 h-2.5" /> {video.views || 0} views
160	          </span>
161	          {video.duration && (
162	            <span className="text-[10px] text-zinc-500 flex items-center gap-1">
163	              <Clock className="w-2.5 h-2.5" /> {video.duration}m
164	            </span>
165	          )}
166	          {video.category && video.category !== "General" && (
167	            <span className="text-[10px] text-zinc-500">{video.category}</span>
168	          )}
169	          {video.videoType === "vsl" && ctaClicks > 0 && (
170	            <span className="text-[10px] flex items-center gap-1" style={{ color: "#a78bfa" }}>
171	              <MousePointer className="w-2.5 h-2.5" /> {ctaClicks} CTA clicks
172	            </span>
173	          )}
174	        </div>
175	        <div className="mt-1.5">
176	          <VideoStatusPills video={video} />
177	        </div>
178	      </div>
179	
180	      {/* Watch rate bar (VSL only) */}
181	      {video.videoType === "vsl" && (
182	        <div className="hidden lg:flex flex-col items-end gap-1 flex-shrink-0 w-20">
183	          <span className="text-[10px] text-zinc-500">Watch Rate</span>
184	          <div className="w-full h-1.5 rounded-full bg-zinc-800 overflow-hidden">
185	            <div className="h-full rounded-full transition-all" style={{ width: `${watchRate}%`, background: `linear-gradient(90deg, ${GOLD}, #a78bfa)` }} />
186	          </div>
187	          <span className="text-xs font-black" style={{ color: watchRate > 60 ? "#34d399" : watchRate > 40 ? GOLD : "#f87171" }}>{watchRate}%</span>
188	        </div>
189	      )}
190	
191	      {/* Actions */}
192	      <div className="flex items-center gap-1.5 flex-shrink-0 opacity-0 group-hover:opacity-100 transition-opacity">
193	        {video.videoType === "vsl" && (
194	          <button onClick={onStudio} title="VSL Studio" className="flex items-center gap-1 px-2.5 py-1.5 rounded-lg text-[11px] font-bold transition-all hover:scale-105" style={{ background: `${GOLD}18`, color: GOLD, border: `1px solid ${GOLD}30` }}>
195	            <Zap className="w-3 h-3" /> Studio
196	          </button>
197	        )}
198	        <button onClick={onAnalytics} title="Analytics" className="flex items-center gap-1 px-2.5 py-1.5 rounded-lg text-[11px] font-bold transition-all hover:scale-105" style={{ background: "rgba(96,165,250,0.12)", color: "#60a5fa", border: "1px solid rgba(96,165,250,0.25)" }}>
199	          <BarChart3 className="w-3 h-3" /> Analytics
200	        </button>
201	        <button onClick={() => onEmbed(video)} title="Embed code" className="w-7 h-7 rounded-lg flex items-center justify-center transition-all hover:scale-105" style={{ background: "rgba(255,255,255,0.06)", border: "1px solid rgba(255,255,255,0.1)" }}>
202	          <Code2 className="w-3 h-3 text-zinc-400" />
203	        </button>
204	        <button onClick={() => onToggleLeadGate(video.id, video.leadGateEnabled)} title={video.leadGateEnabled ? "Remove lead gate" : "Add lead gate"} className="w-7 h-7 rounded-lg flex items-center justify-center transition-all hover:scale-105" style={{ background: video.leadGateEnabled ? "#f59e0b18" : "rgba(255,255,255,0.06)", border: `1px solid ${video.leadGateEnabled ? "#f59e0b40" : "rgba(255,255,255,0.1)"}` }}>
205	          {video.leadGateEnabled ? <Lock className="w-3 h-3 text-amber-400" /> : <Unlock className="w-3 h-3 text-zinc-500" />}
206	        </button>
207	        <button onClick={() => onDelete(video.id)} title="Delete" className="w-7 h-7 rounded-lg flex items-center justify-center text-zinc-600 hover:text-red-400 hover:bg-red-400/10 transition-all">
208	          <Trash2 className="w-3 h-3" />
209	        </button>
210	      </div>
211	    </div>
212	  );
213	}
