215	export default function VideoHosting({ onNavigate }: { onNavigate?: (tab: string) => void } = {}) {
216	  const qc = useQueryClient();
217	  const { toast } = useToast();
218	  const [showCreate, setShowCreate] = useState(false);
219	  const [uploadMethod, setUploadMethod] = useState("url");
220	  const [embedVideo, setEmbedVideo] = useState<any | null>(null);
221	  const [dragOver, setDragOver] = useState(false);
222	  const [typeFilter, setTypeFilter] = useState<"all"|"vsl"|"standard">("all");
223	  const fileInputRef = useRef<HTMLInputElement>(null);
224	  const [form, setForm] = useState({
225	    title: "", description: "", videoUrl: "", thumbnailUrl: "", videoType: "standard",
226	    progressBarEnabled: false, progressBarStyle: "steady", customProgressSegments: "", duration: "", category: "General"
227	  });
228	
229	  const { data: videos = [] } = useQuery<any[]>({ queryKey: ["/api/video-events"] });
230	
231	  const createMut = useMutation({
232	    mutationFn: (data: any) => apiRequest("POST", "/api/video-events", data),
233	    onSuccess: () => {
234	      qc.invalidateQueries({ queryKey: ["/api/video-events"] });
235	      setShowCreate(false);
236	      setForm({ title: "", description: "", videoUrl: "", thumbnailUrl: "", videoType: "standard", progressBarEnabled: false, progressBarStyle: "steady", customProgressSegments: "", duration: "", category: "General" });
237	      toast({ title: "Video added!" });
238	    },
239	  });
240	
241	  const deleteMut = useMutation({
242	    mutationFn: (id: string) => apiRequest("DELETE", `/api/video-events/${id}`),
243	    onSuccess: () => { qc.invalidateQueries({ queryKey: ["/api/video-events"] }); toast({ title: "Video deleted" }); },
244	  });
245	
246	  const leadGateMut = useMutation({
247	    mutationFn: ({ id, enabled }: { id: string; enabled: boolean }) => apiRequest("PATCH", `/api/video-events/${id}`, { leadGateEnabled: enabled }),
248	    onSuccess: (_, { enabled }) => {
249	      qc.invalidateQueries({ queryKey: ["/api/video-events"] });
250	      toast({ title: enabled ? "Lead gate enabled" : "Lead gate disabled" });
251	    },
252	  });
253	
254	  const [uploadingFile, setUploadingFile] = useState(false);
255	
256	  const handleFileDrop = useCallback(async (files: FileList | null) => {
257	    if (!files || files.length === 0) return;
258	    const file = files[0];
259	    if (!file.type.startsWith("video/")) return toast({ title: "Please drop a video file", variant: "destructive" });
260	    setUploadingFile(true);
261	    try {
262	      const fd = new FormData();
263	      fd.append("file", file);
264	      const resp = await fetch("/api/upload/video", { method: "POST", body: fd });
265	      if (!resp.ok) throw new Error("Upload failed");
266	      const { url } = await resp.json();
267	      setForm(f => ({ ...f, videoUrl: url, title: f.title || file.name.replace(/\.[^.]+$/, "") }));
268	      toast({ title: `${file.name} uploaded`, description: "Fill in the title and click Add Video" });
269	    } catch {
270	      toast({ title: "Upload failed", description: "Try again or use a URL instead", variant: "destructive" });
271	    } finally {
272	      setUploadingFile(false);
273	    }
274	  }, [toast]);
275	
276	  const handleCreate = () => {
277	    if (!form.title || !form.videoUrl) return toast({ title: "Title and URL required", variant: "destructive" });
278	    const progressBarConfig = form.progressBarEnabled ? {
279	      enabled: true, style: form.progressBarStyle,
280	      segments: form.progressBarStyle === "custom" ? form.customProgressSegments : PROGRESS_BAR_PRESETS.find(p => p.id === form.progressBarStyle)?.segments
281	    } : null;
282	    createMut.mutate({
283	      title: form.title, description: form.description || null, videoUrl: form.videoUrl, thumbnailUrl: form.thumbnailUrl || null,
284	      duration: form.duration ? Number(form.duration) : null, category: form.category, videoType: form.videoType,
285	      progressBarConfig: progressBarConfig ? JSON.stringify(progressBarConfig) : null, isPublic: false
286	    });
287	  };
288	
289	  const allVideos = videos as any[];
290	  const vslVideos = allVideos.filter(v => v.videoType === "vsl");
291	  const standardVideos = allVideos.filter(v => !v.videoType || v.videoType === "standard");
292	  const totalViews = allVideos.reduce((s, v) => s + (v.views || 0), 0);
293	  const avgWatchRate = allVideos.length > 0 ? Math.round(allVideos.reduce((s, v) => s + (45 + (v.id?.charCodeAt(0) || 1) % 10 * 4), 0) / allVideos.length) : 0;
294	  const filtered = typeFilter === "vsl" ? vslVideos : typeFilter === "standard" ? standardVideos : allVideos;
295	
296	  return (
297	    <div className="space-y-6">
298	
299	      {/* ── Stat header ── */}
300	      <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
301	        {[
302	          { label: "Total Videos",  value: allVideos.length, icon: Video,      color: GOLD },
303	          { label: "VSLs",          value: vslVideos.length, icon: Zap,        color: "#a78bfa" },
304	          { label: "Total Views",   value: totalViews,       icon: Eye,        color: "#34d399" },
305	          { label: "Avg Watch Rate",value: `${avgWatchRate}%`, icon: TrendingUp, color: "#60a5fa" },
306	        ].map(s => (
307	          <div key={s.label} className="rounded-2xl p-4" style={{ background: "#0c0c10", border: `1px solid ${GOLD}14` }}>
308	            <div className="flex items-start justify-between mb-3">
309	              <p className="text-[10px] font-black uppercase tracking-[0.18em]" style={{ color: `${GOLD}55` }}>{s.label}</p>
310	              <div className="w-8 h-8 rounded-xl flex items-center justify-center" style={{ background: `${s.color}14`, border: `1px solid ${s.color}22` }}>
311	                <s.icon className="w-4 h-4" style={{ color: s.color }} />
312	              </div>
313	            </div>
314	            <p className="text-3xl font-black" style={{ background: `linear-gradient(135deg, #fff 0%, ${s.color} 100%)`, WebkitBackgroundClip: "text", WebkitTextFillColor: "transparent", letterSpacing: "-0.02em" }}>{s.value}</p>
315	          </div>
316	        ))}
317	      </div>
318	
319	      {/* ── Library header ── */}
320	      <div className="flex items-center justify-between gap-3">
321	        <div>
322	          <p className="text-[10px] font-black uppercase tracking-[0.25em] mb-0.5" style={{ color: `${GOLD}50` }}>— Library —</p>
323	          <h3 className="text-2xl font-black" style={{ background: `linear-gradient(135deg, #fff 0%, ${GOLD} 100%)`, WebkitBackgroundClip: "text", WebkitTextFillColor: "transparent", letterSpacing: "-0.02em" }}>Video Library</h3>
324	        </div>
325	        <div className="flex items-center gap-2">
326	          <div className="flex rounded-xl overflow-hidden" style={{ border: `1px solid ${GOLD}14`, background: "#0c0c10" }}>
327	            {([["all","All"], ["vsl","VSLs"], ["standard","Standard"]] as [string,string][]).map(([k,l]) => (
328	              <button key={k} onClick={() => setTypeFilter(k as any)} className="px-3 py-1.5 text-xs font-bold transition-all" style={{
329	                background: typeFilter === k ? GOLD : "transparent",
330	                color: typeFilter === k ? "#000" : "#71717a",
331	              }}>{l}</button>
332	            ))}
333	          </div>
334	          <Button size="sm" style={{ background: GOLD, color: "#000" }} className="font-semibold gap-1.5" onClick={() => setShowCreate(true)}>
335	            <Plus className="w-4 h-4" /> Add Video
336	          </Button>
337	        </div>
338	      </div>
339	
340	      {/* ── Video list (table style) ── */}
341	      <div className="rounded-2xl overflow-hidden" style={{ border: `1px solid ${GOLD}14` }}>
342	        {/* Table header */}
343	        <div className="px-5 py-3 hidden md:grid grid-cols-[2fr_1fr_auto] gap-4" style={{ background: "rgba(8,8,12,0.95)", borderBottom: `1px solid ${GOLD}10` }}>
344	          <span className="text-[10px] font-bold text-zinc-600 uppercase tracking-wider">Video</span>
345	          <span className="text-[10px] font-bold text-zinc-600 uppercase tracking-wider hidden lg:block">Watch Rate</span>
346	          <span className="text-[10px] font-bold text-zinc-600 uppercase tracking-wider">Actions</span>
347	        </div>
348	
349	        {filtered.length === 0 ? (
350	          <div className="py-16 text-center">
351	            <div className="w-14 h-14 rounded-2xl flex items-center justify-center mx-auto mb-4" style={{ background: `${GOLD}10`, border: `1px solid ${GOLD}20` }}>
352	              <Film className="w-6 h-6" style={{ color: `${GOLD}80` }} />
353	            </div>
354	            <p className="text-sm font-semibold text-zinc-400 mb-1">{typeFilter === "vsl" ? "No VSLs yet" : "No videos yet"}</p>
355	            <p className="text-xs text-zinc-600">{typeFilter === "vsl" ? "Add a video and set type to VSL" : "Click Add Video to upload your first video"}</p>
356	          </div>
357	        ) : (
358	          <div>
359	            {filtered.map((v: any, i: number) => (
360	              <VideoRow
361	                key={v.id}
362	                video={v}
363	                seed={(v.id?.charCodeAt(0) || i + 1) % 10}
364	                onDelete={(id) => deleteMut.mutate(id)}
365	                onToggleLeadGate={(id, cur) => leadGateMut.mutate({ id, enabled: !cur })}
366	                onEmbed={(vid) => setEmbedVideo(vid)}
367	                onStudio={() => onNavigate?.("vsl-studio")}
368	                onAnalytics={() => onNavigate?.("video-analytics")}
369	              />
370	            ))}
371	          </div>
372	        )}
373	      </div>
374	
375	      {/* ── VSL Showcase (if VSLs exist) ── */}
376	      {vslVideos.length > 0 && (
377	        <VSLShowcase videos={vslVideos} onStudio={() => onNavigate?.("vsl-studio")} />
378	      )}
379	
380	      {embedVideo && <EmbedDialog video={embedVideo} onClose={() => setEmbedVideo(null)} />}
381	
382	      {/* ── Add Video dialog ── */}
383	      <Dialog open={showCreate} onOpenChange={setShowCreate}>
384	        <DialogContent className="bg-zinc-900 border-zinc-700 max-w-2xl max-h-[90vh] overflow-y-auto">
385	          <DialogHeader>
386	            <DialogTitle className="text-white font-bold flex items-center gap-2">
