520	function genRetentionCurve(seed: number): number[] {
521	  const c = [100];
522	  for (let i = 1; i <= 10; i++) {
523	    c.push(Math.max(2, c[i-1] - (4 + ((seed + i) % 7) + Math.abs(Math.sin(i + seed) * 6))));
524	  }
525	  return c;
526	}
