25	function getEmbedUrl(url: string): string {
26	  const yt = url.match(/(?:youtube\.com\/watch\?v=|youtu\.be\/)([^&?/\s]+)/);
27	  if (yt) return `https://www.youtube.com/embed/${yt[1]}?autoplay=1&rel=0`;
28	  const vim = url.match(/vimeo\.com\/(\d+)/);
29	  if (vim) return `https://player.vimeo.com/video/${vim[1]}?autoplay=1`;
30	  return url;
31	}
32	function isDirectVideo(url: string): boolean {
33	  return /\.(mp4|mov|webm|ogg|mkv)(\?.*)?$/i.test(url);
